import './Menu.scss';

import { MenuProvider } from ':components/Menu/MenuContext';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { classNames } from ':helpers/classnames';
import React, { useEffect, useRef, useState } from 'react';

import type { MenuProps } from './Menu.types';
import { getMaxDepth, processChildrenWithProps } from './MenuUtils';

export const Menu: React.FC<MenuProps> = ({
	parent,
	children,
	isOpen,
	onOutsideClick,
	className,
	internalPosition,
	onOpen,
	onClose,
	onEscape,
	id = '',
	widthMode = 'widthParent',
	nestedPosition = 'auto',
	align = 'bottom-start',
	dataTestId = 'Menu',
}) => {
	const [horizontalOffset, setHorizontalOffset] = useState(0);
	const [menuAlign, setMenuAlign] = useState<'right' | 'left'>();
	const [menuWidth, setMenuWidth] = useState<number>();
	const menuRef = useRef<HTMLUListElement>(null);
	const parentRef = useRef<HTMLDivElement>(null);

	useEffect(() => {
		isOpen ? onOpen?.() : onClose?.();
	}, [isOpen]);

	useEffect(() => {
		if (!onEscape || !isOpen) {
			return;
		}
		const handleKeyDown = event => {
			if (event.key === 'Escape') {
				onEscape?.();
			}
		};

		globalThis.addEventListener('keydown', handleKeyDown, true);

		return () => {
			globalThis.removeEventListener('keydown', handleKeyDown, true);
		};
	}, [onEscape, isOpen]);

	useEffect(() => {
		const positionCriteria = nestedPosition === 'auto' ? menuAlign : nestedPosition;
		setHorizontalOffset(positionCriteria === 'right' ? menuWidth : -menuWidth);
	}, [menuWidth, menuAlign]);

	useEffect(() => {
		requestAnimationFrame(() => {
			if (isOpen && menuRef.current && parent.current) {
				setMenuWidth(menuRef.current.offsetWidth);
				const parentRect = parent.current.getBoundingClientRect();
				const windowWidth = window.innerWidth;

				const spaceRight = windowWidth - parentRect.right;

				if (nestedPosition === 'auto') {
					setMenuAlign(spaceRight - menuWidth * getMaxDepth(children) > 0 ? 'right' : 'left');
				} else {
					setMenuAlign(nestedPosition);
				}
			}
		});
	}, [isOpen, parent, menuAlign, horizontalOffset, internalPosition, children]);

	const additionalProps = { internalPosition: menuAlign };
	const childrenWithProps = processChildrenWithProps(children, additionalProps, id);

	const MenuComponent = (
		<>
			{isOpen && (
				<NewDropdownMenu
					widthMode={widthMode}
					verticalOffset={internalPosition ? -54 : 0}
					horizontalOffset={internalPosition ? horizontalOffset : 0}
					onOutsideClick={onOutsideClick}
					className={classNames('menu', className, (!horizontalOffset || !menuAlign) && 'menu-inactive')}
					isOpen={isOpen}
					handleSetOpen={null}
					targetElement={parent}
					align={align}
					aria-expanded={isOpen}
				>
					<div ref={parentRef} data-testid={dataTestId}>
						<ul role="menu" ref={menuRef}>
							{childrenWithProps}
						</ul>
					</div>
				</NewDropdownMenu>
			)}
		</>
	);

	return <MenuProvider>{MenuComponent}</MenuProvider>;
};
